function a(r){if(r==null||r==="")return"-";const e=new Date(r);if(isNaN(e.getTime()))return"-";const t=n=>String(n).padStart(2,"0");return`${e.getFullYear()}-${t(e.getMonth()+1)}-${t(e.getDate())} ${t(e.getHours())}:${t(e.getMinutes())}`}function i(r){const e=Date.now()-new Date(r).getTime(),t=Math.floor(e/6e4);if(t<1)return"刚刚";if(t<60)return`${t} 分钟前`;const n=Math.floor(t/60);if(n<24)return`${n} 小时前`;const o=Math.floor(n/24);return o<30?`${o} 天前`:a(r)}export{i as a,a as f};
